const DEFAULT_UNITS = ['Pcs', 'Kg', 'Gm', 'Mg', 'Ton', 'Ltr', 'Ml', 'Mtr', 'Cm', 'Ft', 'Inch', 'Bag', 'Box', 'Set', 'Doz', 'Pair', 'Pack', 'Roll', 'Sheet', 'Bundle', 'Carton', 'Bottle', 'Can', 'Tube', 'Sack', 'Plate', 'Unit'];

/* ══ Other forms — unchanged ════════════════════════════════════════════════ */
export const InventoryForm = ({ formData, handleChange, units, onAddUnit }: any) => {
  const unitList: string[] = units && units.length > 0 ? units : DEFAULT_UNITS;
  const currentUnit: string = formData.unit || 'Pcs';
  const isNewUnit = currentUnit.trim().length > 0 && !unitList.map((u: string) => u.toLowerCase()).includes(currentUnit.trim().toLowerCase());

  return (
  <div className="space-y-4">
    <InputField label="Item Name" field="name" icon={Package} value={formData.name} onChange={handleChange} placeholder="e.g. Cement Bag 50kg"/>
    <div className="grid grid-cols-2 gap-3">
      <div className="mb-3">
        <label className="block text-xs font-bold text-[rgba(148,163,184,0.45)] mb-1">Unit</label>
        <div className="flex gap-1.5">
          <input
            type="text"
            list="inv_unit_options"
            className="flex-1 min-w-0 border border-white/12 bg-[rgba(255,255,255,0.05)] p-2.5 rounded-lg text-sm font-bold text-[rgba(226,232,240,0.88)] outline-none"
            value={currentUnit}
            onChange={e => handleChange('unit', e.target.value)}
            placeholder="Pcs, Kg, Bag…"
          />
          <datalist id="inv_unit_options">
            {unitList.map((u: string) => <option key={u} value={u}/>)}
          </datalist>
          <button
            type="button"
            title={isNewUnit ? `Add "${currentUnit.trim()}" to unit list` : 'Type a new unit to add it'}
            onClick={() => isNewUnit && onAddUnit?.(currentUnit.trim())}
            className="flex items-center justify-center w-9 rounded-lg border transition-all flex-shrink-0"
            style={isNewUnit
              ? { background: 'rgba(99,102,241,0.2)', borderColor: 'rgba(99,102,241,0.4)', color: '#a78bfa' }
              : { background: 'rgba(255,255,255,0.04)', borderColor: 'rgba(255,255,255,0.1)', color: 'rgba(148,163,184,0.25)', cursor: 'default' }}
          >
            <Plus size={14}/>
          </button>
        </div>
        {isNewUnit && (
          <p className="text-[10px] mt-1 font-semibold" style={{ color: 'rgba(167,139,250,0.7)' }}>
            Tap + to save "{currentUnit.trim()}" to your unit list
          </p>
        )}
      </div>
      <InputField label="HSN Code" field="hsn_code" icon={Hash} value={formData.hsn_code} onChange={handleChange}/>

{type === 'inventory' && <InventoryForm
  formData={formData}
  handleChange={handleChange}
  units={inventoryUnits}
  onAddUnit={handleAddUnit}
/>}

