    45→function fmtPdfDate(raw: any): string {
    46→  if (!raw) return '-';
    47→  const d = parseDateSafe(raw);
    48→  if (isNaN(d.getTime())) return '-';
    49→  return d.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });
