    51→
    52→function fmtRsPdf(n: any): string {
    53→  const num = Math.abs(Number(n || 0));
    54→  const [intPart, decPart] = num.toFixed(2).split('.');
    55→  let formatted = '';
    56→  if (intPart.length <= 3) {
    57→    formatted = intPart;
    58→  } else {
    59→    formatted = intPart.slice(-3);
    60→    let rest = intPart.slice(0, -3);
    61→    while (rest.length > 2) { formatted = rest.slice(-2) + ',' + formatted; rest = rest.slice(0, -2); }
    62→    if (rest.length > 0) formatted = rest + ',' + formatted;
    63→  }
    64→  return `Rs.${formatted}.${decPart}`;
    65→}
